unsafe_example:
// UNSAFE: logging raw HTTP parameter that may contain a password
String password = request.getParameter("password");
logger.info("Login attempt for user {} with password {}", username, password);

safe_example:
// SAFE: log only non-sensitive identifiers, redact sensitive fields
String username = request.getParameter("username");
logger.info("Login attempt for user {}", username);
// Never log passwords, tokens, or session IDs
// If debugging is needed, log a hash or masked version:
logger.debug("Login attempt for user {}, password length={}", username, password.length());
